class Descriptor:
    def __init__(self, initval=None):
        self.val = initval
    def __get__(self, obj, objtype):
        return self.val
    def __set__(self, obj, value):
        self.val = value

class MyClass:
    attr = Descriptor(0)

obj = MyClass()
print(obj.attr)
obj.attr = 10
print(obj.attr)
